sql:
SELECT search_query
FROM search_logs
WHERE search_date = '2023-05-02';

SELECT city_name, population
FROM cities
WHERE city_id = '1';

SELECT user_id, COUNT(search_id) AS total_searches
FROM search_logs
GROUP BY user_id;

SELECT airport_id
FROM search_results
ORDER BY score DESC;

SELECT airport_id, AVG(rating) AS average_rating
FROM airport_reviews
GROUP BY airport_id;

SELECT COUNT(review_id) AS total_reviews
FROM airport_reviews
WHERE airport_id = 1;

SELECT user_name
FROM users
WHERE user_id = (
  SELECT user_id
  FROM airport_reviews
  WHERE review_date = (
    SELECT MAX(review_date) FROM airport_reviews
  )
);

SELECT COUNT(*) AS total_searches
FROM search_logs
WHERE user_id = 1;

external_knowledge:
- "most sought after" refers to the airport with the highest search frequency; 
- "admired" refers to the airport that has been marked as favorite the most times by users; 
- "talked about" refers to the airport with the highest number of reviews; 
- "well-liked" refers to the airport with the highest average rating.

Airport ratings are based on a 1-5 scale; 
Users who reviewed more than 5 airports are considered frequent reviewers; 
Average rating, search count, and favorite count are key indicators of an airport's performance.
